static int uri_format(char *buf, size_t buf_size, const char *fmt, va_list args)
{
    char *out, *end;
    va_list args_copy;
    int c, n, used;

    out = buf;
    end = buf + buf_size - 1;
    if (!buf || !buf_size || !fmt)
        return -EINVAL;

    va_copy(args_copy, args);
    while ((c = *fmt++) != '\0') {
        if (c != '%') {
            if (out < end)
                *out++ = c;
            continue;
        }
        c = *fmt++;
        if (!c)
            break;
        used = 0;
        if (c == '%') {
            if (out < end)
                *out++ = c;
            used = 1;
        } else if (strchr("uioU", c)) {
            n = vsnprintf(out, end - out + 1, "%c", args_copy);
            if (n > 0) {
                out += n;
                used = 1;
            }
        }
        if (used) {
            va_copy(args_copy, args);
            continue;
        }
        /* unknown conversion specifier, ignore it */
        if (c == '}')
            fmt++; /* skip past closing brace */
        while (*fmt && *fmt != '%')
            fmt++;
    }
    *out = '\0';
    return out - buf;
