#include <stdio.h>

#define CP_TAG_UTF8 1
#define CP_TAG_LONG 6
#define CP_TAG_NAME_AND_TYPE 12

typedef unsigned char u1;
typedef unsigned int u2;

static inline u2 r_bin_java_get_cp_index(u1 tag, const u1 *cp_info) {
    u2 idx;
    switch (tag) {
    case CP_TAG_UTF8:
    case CP_TAG_NAME_AND_TYPE:
        idx = ((u2)*(cp_info + 1) << 8) | (u2)*(cp_info + 2);
        break;
    case CP_TAG_LONG:
        idx = ((u2)*(cp_info + 1) << 8) | (u2)*(cp_info + 2);
        cp_info += 7; // Skip 7 bytes for long
        break;
    default:
        idx = 0;
        break;
    }
    return idx;
}
