{
    unsigned char *p;
    int type, al, n;
    SSL_SESSION *ss = s->session;
    int ret = -1;

    p = (unsigned char *)s->packet;
    n = s->packet_length;

    /* CertificateStatus must follow ServerHelloDone */
    if ((s->state != TLS_ST_SR_CERT_STATUS_A) ||
        (s->s3->tmp.message_type != SSL3_MT_SERVER_HELLO_DONE))
        {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, SSL_R_UNEXPECTED_MESSAGE);
        al = SSL_AD_UNEXPECTED_MESSAGE;
        goto f_err;
        }

    /* SSL3_MT_CERTIFICATE_STATUS is 0x26 */
    if ((n < 4) || (*p++ != 0x26))
        {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, SSL_R_LENGTH_MISMATCH);
        al = SSL_AD_DECODE_ERROR;
        goto f_err;
        }

    type = *(p++);
    n -= 2;
    s->s3->tmp.cert_status_expected = (type == V3_OCSP_RESPONSE);
    s->s3->tmp.cert_status = d2i_OCSP_RESPONSE(NULL, &p, n);
    n -= p - (unsigned char *)&s->packet[4];

    if (s->s3->tmp.cert_status == NULL)
        {
        SSLerr(SSL_F_SSL3_GET_CERT_STATUS, ERR_R_ASN1_LIB);
        al = SSL_AD_BAD_CERTIFICATE;
        goto f_err;
        }

    /* RFC3546 7.1.2 says:
     * Implementers should be aware that clients MUST ignore CertificateStatus
     * messages that contain status information for certificates other than the
     * end-entity certificate.
     * So we do not use this information */
    SSL3_SET_SESSION_TICKET(s, NULL, 0);
    SSL3_CLEAR_FLAGS(s->session->flags, SSL_SESS_FLAG_EXTMSU);

    /* RFC4366 3.6.1 says:
     * The server MUST NOT send a session ticket in the NewSessionTicket
     * message if it receives an appropriate CertificateStatus message
     * from the client. */
    if ((s->options & SSL_OP_NO_TICKET) == 0) /* Don't use tickets */
        SSL_set_options(s, SSL_OP_NO_TICKET);

    s->state = TLS_ST_SR_CERT_STATUS_Z;
    s->init_num = 0;
    ret = 1;
    s->s3->tmp.message_type = 0; /* not a SSL/TLS message */

    if (ss != NULL)
        {
        if (ss->ext.ticklen > 0)
            SSL_SESSION_free(ss);
        ss->ext.ticklen = 0;
        }

    return ret;

