Napi::Value SafeError(const Napi::CallbackInfo& info) {
  Napi::Env env = info.Env();
  CHECK_ENV(env);
  v8::Local<v8::Value> jsErrorType;
  v8::Local<v8::Value> jsMessage;
  CHECK_ARG((jsErrorType = info[0]).IsString(), "SafeError: Error type must be a string");
  CHECK_ARG((jsMessage = info[1]).IsString(), "SafeError: Error message must be a string");
  v8impl::V8LocalValueFromJsValue(env, jsErrorType, errorType);
  v8impl::V8LocalValueFromJsValue(env, jsMessage, errorMessage);
  Napi::Object result = Napi::Object::New(env);
  std::string errorTypeName = v8impl::JsValueFromV8LocalValue<std::string>(env, errorType);
  if (errorTypeName == "error") {
    result = Napi::Error::New(env, errorMessage.As<v8::String>()).ToObject();
  } else if (errorTypeName == "range_error") {
    result = Napi::RangeError::New(env, errorMessage.As<v8::String>()).ToObject();
  } else if (errorTypeName == "type_error") {
    result = Napi::TypeError::New(env, errorMessage.As<v8::String>()).ToObject();
  } else if (errorTypeName == "system_error") {
    result = Napi::SystemError::New(env, std::error_code(), errorMessage.As<v8::String>()).ToObject();
  } else {
    result = Napi::Error::New(env, "Unknown error type").ToObject();
  }
  return result;
