static int tls_construct_change_cipher_spec(SSL *s, unsigned char *p, int *len, int *al, int w, int ContentType) {
    SSL3_RECORD *wr;
    unsigned char *s3 = s->s3->write_hash;

    wr = &(s->s3->wrec);
    if (SSL_USE_SIGALGS(s) && ContentType != SSL3_CT_CHANGE_CIPHER_SPEC) {
        *al = SSL_AD_UNEXPECTED_MESSAGE;
        SSLerr(SSL_F_TLS_CONSTRUCT_CHANGE_CIPHER_SPEC, SSL_R_UNEXPECTED_MESSAGE);
        return (SSL_R_UNEXPECTED_MESSAGE);
    }
    *len = 1;
    s2n(1, p,.ContentType);
    wr->data[0] = ContentType;
    SSL3_RECORD_set_header(wr, ContentType, SSL3_RT_CHANGE_CIPHER_SPEC, 1, wr->length = (unsigned int)*len, s->s3->write_sequence);
    s->s3->write_sequence++;
    /*-
     * Mac length is not needed when signing, but it's easier to just always
     * calculate it.  It doesn't get written out anyway
     */
    if (!SSL_USE_ETM(s) && !s->s3->flags & TLS1_FLAGS_SCT_PROTECTED) {
        if (!tls1_mac(s, s3, ContentType, wr->data, wr->length, &(wr->exclusive_buf[0]), wr->length + SSL3_RT_HEADER_LENGTH)) {
            *al = SSL_AD_INTERNAL_ERROR;
            return SSL_R_DIGEST_FAILED;
        }
    }
    if (!ssl3_output_cert_verify(s, al)) {
        return (-1);
    }
    return (wr->length + SSL3_RT_HEADER_LENGTH);
}
