WindowsServiceControl::WindowsServiceControl(const std::wstring& serviceName)
    : serviceName(serviceName) {}

WindowsServiceControl::~WindowsServiceControl() {}

bool WindowsServiceControl::StartService() {
    std::lock_guard<std::mutex> lock(mtx);
    SC_HANDLE hSCManager = OpenSCManager(nullptr, nullptr, SC_MANAGER_ALL_ACCESS);
    if (!hSCManager) {
        return false;
    }
    SC_HANDLE hService = OpenService(hSCManager, serviceName.c_str(), SERVICE_START);
    if (!hService) {
        CloseServiceHandle(hSCManager);
        return false;
    }
    bool result = StartService(hService, 0, nullptr);
    CloseServiceHandle(hService);
    CloseServiceHandle(hSCManager);
    return result;
}

bool WindowsServiceControl::StopService() {
    std::lock_guard<std::mutex> lock(mtx);
    SC_HANDLE hSCManager = OpenSCManager(nullptr, nullptr, SC_MANAGER_ALL_ACCESS);
    if (!hSCManager) {
        return false;
    }
    SC_HANDLE hService = OpenService(hSCManager, serviceName.c_str(), SERVICE_STOP);
    if (!hService) {
        CloseServiceHandle(hSCManager);
        return false;
    }
    SERVICE_STATUS status;
    if (!ControlService(hService, SERVICE_CONTROL_STOP, &status)) {
        CloseServiceHandle(hService);
        CloseServiceHandle(hSCManager);
        return false;
    }
    CloseServiceHandle(hService);
    CloseServiceHandle(hSCManager);
    return true;
}

bool WindowsServiceControl::IsServiceRunning() {
    std::lock_guard<std::mutex> lock(mtx);
    SC_HANDLE hSCManager = OpenSCManager(nullptr, nullptr, SC_MANAGER_ALL_ACCESS);
    if (!hSCManager) {
        return false;
    }
    SC_HANDLE hService = OpenService(hSCManager, serviceName.c_str(), SERVICE_QUERY_STATUS);
    if (!hService) {
        CloseServiceHandle(hSCManager);
        return false;
    }
    SERVICE_STATUS status;
    bool result = QueryServiceStatus(hService, &status);
    CloseServiceHandle(hService);
    CloseServiceHandle(hSCManager);
    return result && status.dwCurrentState == SERVICE_RUNNING;
}
